    pub check_latency: bool,
    /// Maximum tolerated SendingTime latency, in seconds.
    pub max_latency: u32,
    /// Seconds to wait for the Logon handshake before giving up (LogonTimeout).
    pub logon_timeout: u32,
    /// Seconds to wait for the counterparty Logout before disconnecting (LogoutTimeout).
    pub logout_timeout: u32,
    /// Initiator reconnect interval, in seconds (ReconnectInterval).
    pub reconnect_interval: u32,
    /// Optional activity schedule (StartTime/EndTime/Weekdays/NonStop).
    pub schedule: Option<crate::schedule::Schedule>,
}

impl SessionConfig {
    /// Convenience constructor.
    pub fn new(
        begin_string: impl Into<String>,
        sender_comp_id: impl Into<String>,
        target_comp_id: impl Into<String>,
        role: Role,
    ) -> Self {
        Self {
            begin_string: begin_string.into(),
            sender_comp_id: sender_comp_id.into(),
            target_comp_id: target_comp_id.into(),
            heartbeat_interval: 30,
            role,
            reset_on_logon: true,
            reset_on_logout: false,
            reset_on_disconnect: false,
            refresh_on_logon: false,
            resend_request_chunk_size: 0,
            enable_next_expected_msg_seq_num: false,
            enable_last_msg_seq_num_processed: false,
            check_latency: true,
            max_latency: 120,
            logon_timeout: 10,
            logout_timeout: 10,
            reconnect_interval: 5,
            schedule: None,
        }
    }

    /// The [`SessionId`] this configuration describes.
    pub fn session_id(&self) -> SessionId {
        SessionId::new(
            self.begin_string.clone(),
            self.sender_comp_id.clone(),
            self.target_comp_id.clone(),
        )
    }
}

//! The integrator callback surface.

use truefix_core::Message;

use crate::session_id::SessionId;

/// Application callbacks invoked by the engine over a session's lifecycle.
///
/// All methods are async (FR-F7). Default implementations are no-ops so simple integrators
/// only override what they need. Inbound/outbound *admin* messages flow through
/// [`from_admin`](Application::from_admin) / [`to_admin`](Application::to_admin); application
/// messages through [`from_app`](Application::from_app) / [`to_app`](Application::to_app).
#[async_trait::async_trait]
pub trait Application: Send + Sync {
    /// Called once when a session is created.
    async fn on_create(&self, _session: &SessionId) {}

    /// Called when the session successfully logs on.
    async fn on_logon(&self, _session: &SessionId) {}

    /// Called when the session logs out or disconnects.
    async fn on_logout(&self, _session: &SessionId) {}

    /// Called before an outbound admin message is sent (allows mutation, e.g. credentials).
    async fn to_admin(&self, _message: &mut Message, _session: &SessionId) {}

    /// Called for an inbound admin message. Returning `Err` rejects the message
    /// (e.g. failed authentication on Logon).
    // `from_admin` is the established FIX callback name; it intentionally takes `&self`.
    #[allow(clippy::wrong_self_convention)]
    async fn from_admin(&self, _message: &Message, _session: &SessionId) -> Result<(), String> {
        Ok(())
    }

    /// Called before an outbound application message is sent.
    async fn to_app(&self, _message: &mut Message, _session: &SessionId) {}

    /// Called for an inbound application message.
    // `from_app` is the established FIX callback name; it intentionally takes `&self`.
    #[allow(clippy::wrong_self_convention)]
    async fn from_app(&self, _message: &Message, _session: &SessionId) -> Result<(), String> {
        Ok(())
    }
}

//! Authored acceptance-test scenarios (black-box behaviour contracts).
//!
//! These reproduce the *behaviour* of the classic QuickFIX server AT scenarios from the FIX
//! specification — independently scripted, with no source or test data copied (Constitution
//! Principle III). This is a representative core subset (logon, sequence handling, test request,
//! logout); porting the full 73-scenario corpus is incremental authoring on top of this runner.

use truefix_core::{Field, Message};

use crate::runner::{client_message, ExpectMsg, Scenario, Step};

/// The FIX versions the server suite is exercised against.
pub const SUITE_VERSIONS: &[&str] = &["FIX.4.2", "FIX.4.4"];

fn logon(version: &str, seq: i64, reset: bool) -> Message {
    let mut m = client_message(version, "A", seq);
    m.body.set(Field::int(98, 0));
    m.body.set(Field::int(108, 30));
    if reset {
        m.body.set(Field::string(141, "Y"));
    }
    m
}

fn scenario(name: &str, version: &str, steps: Vec<Step>) -> Scenario {
    Scenario {
        name: name.to_owned(),
        versions: vec![version.to_owned()],
        steps,
    }
}

/// 1a — a valid Logon with the correct MsgSeqNum is answered with a Logon.
fn valid_logon(v: &str) -> Scenario {
    scenario(
        "1a_ValidLogonWithCorrectMsgSeqNum",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
        ],
    )
}

/// 1a — a Logon whose MsgSeqNum is too high logs on, then a ResendRequest is issued.
fn logon_seq_too_high(v: &str) -> Scenario {
    scenario(
        "1a_ValidLogonMsgSeqNumTooHigh",
        v,
        vec![
            Step::Send(logon(v, 10, false)), // no reset; expected is 1
            Step::Expect(ExpectMsg::of("A")),
            Step::Expect(ExpectMsg::of("2").field(7, "1")), // ResendRequest BeginSeqNo=1
        ],
    )
}

/// 2b — an application/admin message with MsgSeqNum too high triggers a ResendRequest.
fn msgseqnum_too_high(v: &str) -> Scenario {
    scenario(
        "2b_MsgSeqNumTooHigh",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(client_message(v, "0", 10)), // Heartbeat, seq too high
            Step::Expect(ExpectMsg::of("2").field(7, "2")), // ResendRequest BeginSeqNo=2
        ],
    )
}

/// 2c — a message with MsgSeqNum too low (no PossDup) draws a Logout and disconnect.
fn msgseqnum_too_low(v: &str) -> Scenario {
    scenario(
        "2c_MsgSeqNumTooLow",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(client_message(v, "0", 1)), // Heartbeat, seq too low
            Step::Expect(ExpectMsg::of("5")),      // Logout
            Step::ExpectDisconnect,
        ],
    )
}

/// 4b — a received TestRequest is answered with a Heartbeat echoing the TestReqID.
fn received_test_request(v: &str) -> Scenario {
    let mut tr = client_message(v, "1", 2);
    tr.body.set(Field::string(112, "HELLO"));
    scenario(
        "4b_ReceivedTestRequest",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(tr),
            Step::Expect(ExpectMsg::of("0").field(112, "HELLO")),
        ],
    )
}

/// 13b — an unsolicited Logout is answered with a Logout and disconnect.
fn unsolicited_logout(v: &str) -> Scenario {
    scenario(
        "13b_UnsolicitedLogoutMessage",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(client_message(v, "5", 2)), // Logout
            Step::Expect(ExpectMsg::of("5")),
            Step::ExpectDisconnect,
        ],
    )
}

/// A valid FIX.4.4 NewOrderSingle (all required fields present).
fn new_order_single(seq: i64) -> Message {
    let mut m = client_message("FIX.4.4", "D", seq);
    m.body.set(Field::string(11, "ORDER-1")); // ClOrdID
    m.body.set(Field::string(21, "1")); // HandlInst
    m.body.set(Field::string(55, "AAPL")); // Symbol
    m.body.set(Field::string(54, "1")); // Side
    m.body.set(Field::string(60, "20240101-00:00:00")); // TransactTime
    m.body.set(Field::string(40, "2")); // OrdType
    m
}

/// 14b — a NewOrderSingle missing a required field draws a session-level Reject.
fn required_field_missing(v: &str) -> Scenario {
    let mut order = new_order_single(2);
    order.body = {
        // rebuild body without HandlInst(21)
        let mut b = truefix_core::FieldMap::new();
        for f in new_order_single(2).body.fields() {
            if f.tag() != 21 {
                b.set(Field::new(f.tag(), f.value_bytes().to_vec()));
            }
        }
        b
    };
    scenario(
        "14b_RequiredFieldMissing",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(order),
            Step::Expect(ExpectMsg::of("3").field(373, "1")), // Reject: RequiredTagMissing
        ],
    )
}

/// 14e — a field with an out-of-range enumerated value draws a session-level Reject.
fn incorrect_enum_value(v: &str) -> Scenario {
    let mut order = new_order_single(2);
    order.body.set(Field::string(54, "9")); // Side not in {1,2,5,6}
    scenario(
        "14e_IncorrectEnumValue",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(order),
            Step::Expect(ExpectMsg::of("3").field(373, "5")), // Reject: ValueIsIncorrect
        ],
    )
}

/// 14a — a field whose tag is not defined in the dictionary draws a session-level Reject.
fn invalid_tag_number(v: &str) -> Scenario {
    let mut order = new_order_single(2);
    order.body.set(Field::string(999, "X")); // 999 undefined, below the UDF range
    scenario(
        "14a_InvalidTagNumber",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(order),
            Step::Expect(ExpectMsg::of("3").field(373, "0")), // Reject: InvalidTagNumber
        ],
    )
}

/// 14c — a defined field that is not valid for this message type draws a session-level Reject.
fn tag_not_defined_for_msg_type(v: &str) -> Scenario {
    let mut order = new_order_single(2);
    order.body.set(Field::string(112, "X")); // TestReqID is defined but not part of NewOrderSingle
    scenario(
        "14c_TagNotDefinedForMsgType",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(order),
            Step::Expect(ExpectMsg::of("3").field(373, "2")), // Reject: TagNotDefinedForMessageType
        ],
    )
}

/// 14d — a field present with no value draws a session-level Reject.
fn tag_specified_without_value(v: &str) -> Scenario {
    let mut order = new_order_single(2);
    order.body.set(Field::new(11, Vec::new())); // ClOrdID present but empty
    scenario(
        "14d_TagSpecifiedWithoutValue",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(order),
            Step::Expect(ExpectMsg::of("3").field(373, "4")), // Reject: TagSpecifiedWithoutValue
        ],
    )
}

/// 14f — a field whose value has the wrong data format draws a session-level Reject.
fn incorrect_data_format(v: &str) -> Scenario {
    let mut order = new_order_single(2);
    order.body.set(Field::string(38, "abc")); // OrderQty is a QTY; "abc" is not numeric
    scenario(
        "14f_IncorrectDataFormat",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(order),
            Step::Expect(ExpectMsg::of("3").field(373, "6")), // Reject: IncorrectDataFormat
        ],
    )
}

/// 2r — an unregistered (unknown) MsgType draws a Business Message Reject.
fn unregistered_msg_type(v: &str) -> Scenario {
    scenario(
        "2r_UnregisteredMsgType",
        v,
        vec![
            Step::Send(logon(v, 1, true)),
            Step::Expect(ExpectMsg::of("A")),
            Step::Send(client_message(v, "UU", 2)), // unknown application MsgType
            Step::Expect(ExpectMsg::of("j")),       // BusinessMessageReject
        ],
    )
}

/// The (representative) server acceptance-test suite across [`SUITE_VERSIONS`].
pub fn server_suite() -> Vec<Scenario> {
    let mut out = Vec::new();
    for &v in SUITE_VERSIONS {
        out.push(valid_logon(v));
        out.push(logon_seq_too_high(v));
        out.push(msgseqnum_too_high(v));
        out.push(msgseqnum_too_low(v));
        out.push(received_test_request(v));
        out.push(unsolicited_logout(v));
    }
    // Field-validation scenarios require the dictionary; authored for FIX.4.4.
    out.push(required_field_missing("FIX.4.4"));
    out.push(incorrect_enum_value("FIX.4.4"));
    out.push(invalid_tag_number("FIX.4.4"));
    out.push(tag_not_defined_for_msg_type("FIX.4.4"));
    out.push(tag_specified_without_value("FIX.4.4"));
    out.push(incorrect_data_format("FIX.4.4"));
    out.push(unregistered_msg_type("FIX.4.4"));
    out
}

//! Build-time codegen (dual-track, Constitution Principle IV).
//!
//! Reads the same normalized dictionary sources the runtime loads, and generates per-version
//! message-type constants plus a content hash. The runtime asserts its parsed hash equals the
//! generated one, proving codegen and runtime derive from one source.

use std::env;
use std::fmt::Write as _;
use std::fs;
use std::path::Path;

fn fnv1a(bytes: &[u8]) -> u64 {
    let mut hash: u64 = 0xcbf2_9ce4_8422_2325;
    for &b in bytes {
        hash ^= u64::from(b);
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

fn main() {
    let manifest = env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR");
    let out_dir = env::var("OUT_DIR").expect("OUT_DIR");
    let mut code = String::new();
    code.push_str("// @generated by build.rs from dict-src/normalized — do not edit.\n");

    for (name, file) in [
        ("FIX40", "FIX40.fixdict"),
        ("FIX41", "FIX41.fixdict"),
        ("FIX42", "FIX42.fixdict"),
        ("FIX43", "FIX43.fixdict"),
        ("FIX44", "FIX44.fixdict"),
        ("FIXT11", "FIXT11.fixdict"),
        ("FIX50", "FIX50.fixdict"),
        ("FIX50SP1", "FIX50SP1.fixdict"),
        ("FIX50SP2", "FIX50SP2.fixdict"),
    ] {
        let path = Path::new(&manifest).join("dict-src/normalized").join(file);
        println!("cargo:rerun-if-changed={}", path.display());
        let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {}: {e}", path.display()));
        let hash = fnv1a(&bytes);
        let _ = writeln!(code, "/// Content hash of the {name} dictionary source.");
        let _ = writeln!(code, "pub const {name}_DICT_HASH: u64 = {hash};");

        let module = name.to_lowercase();
        let _ = writeln!(
            code,
            "/// Generated MsgType constants for the {name} dictionary."
        );
        let _ = writeln!(code, "pub mod {module}_msgs {{");
        for line in String::from_utf8_lossy(&bytes).lines() {
            let line = line.trim();
            if let Some(rest) = line.strip_prefix("message ") {
                let mut it = rest.split_whitespace();
                if let (Some(msg_type), Some(msg_name)) = (it.next(), it.next()) {
                    let ident = msg_name.to_uppercase();
                    let _ = writeln!(code, "    /// MsgType for {msg_name}.");
                    let _ = writeln!(code, "    pub const {ident}: &str = {msg_type:?};");
                }
            }
        }
        let _ = writeln!(code, "}}");
    }

    let dest = Path::new(&out_dir).join("generated.rs");
    fs::write(&dest, code).unwrap_or_else(|e| panic!("write generated.rs: {e}"));
}

//! The normalized dictionary model and validation types.

use std::collections::{BTreeMap, BTreeSet};

use truefix_core::Field;

/// A FIX field's value type (drives format validation).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FieldType {
    /// Integer.
    Int,
    /// Length.
    Length,
    /// Sequence number.
    SeqNum,
    /// Repeating-group count.
    NumInGroup,
    /// Float.
    Float,
    /// Price.
    Price,
    /// Quantity.
    Qty,
    /// Amount.
    Amt,
    /// Percentage.
    Percentage,
    /// Single character.
    Char,
    /// Boolean (`Y`/`N`).
    Boolean,
    /// String.
    String,
    /// Binary data.
    Data,
    /// UTC timestamp.
    UtcTimestamp,
    /// UTC time-only.
    UtcTimeOnly,
    /// UTC date-only.
    UtcDateOnly,
    /// Month-year.
    MonthYear,
}

impl FieldType {
    /// Parse a normalized type token (e.g. `"PRICE"`).
    pub fn parse(token: &str) -> Option<Self> {
        Some(match token {
            "INT" => Self::Int,
            "LENGTH" => Self::Length,
            "SEQNUM" => Self::SeqNum,
            "NUMINGROUP" => Self::NumInGroup,
            "FLOAT" => Self::Float,
            "PRICE" => Self::Price,
            "QTY" => Self::Qty,
            "AMT" => Self::Amt,
            "PERCENTAGE" => Self::Percentage,
            "CHAR" => Self::Char,
            "BOOLEAN" => Self::Boolean,
            "STRING" => Self::String,
            "DATA" => Self::Data,
            "UTCTIMESTAMP" => Self::UtcTimestamp,
            "UTCTIMEONLY" => Self::UtcTimeOnly,
            "UTCDATEONLY" => Self::UtcDateOnly,
            "MONTHYEAR" => Self::MonthYear,
            _ => return None,
        })
    }

    /// Whether `field`'s value is well-formed for this type.
    pub fn value_ok(self, field: &Field) -> bool {
        match self {
            Self::Int | Self::Length | Self::SeqNum | Self::NumInGroup => field.as_int().is_ok(),
            Self::Float | Self::Price | Self::Qty | Self::Amt | Self::Percentage => {
                field.as_decimal().is_ok()
            }
            Self::Char => field.as_char().is_ok(),
            Self::Boolean => field.as_bool().is_ok(),
            Self::UtcTimestamp => field.as_utc_timestamp().is_ok(),
            // String/Data/date/time-only are accepted as-is at this layer.
            _ => true,
        }
    }
}

/// A field definition.
#[derive(Debug, Clone)]
pub struct FieldDef {
    /// Tag number.
    pub tag: u32,
    /// Field name.
    pub name: String,
    /// Value type.
    pub field_type: FieldType,
    /// Allowed enumerated values (empty = any value of the type).
    pub values: Vec<String>,
}

impl FieldDef {
    /// Whether `value` is allowed (always true when the field is not enumerated).
    pub fn allows(&self, value: &str) -> bool {
        self.values.is_empty() || self.values.iter().any(|v| v == value)
    }
}

/// A message definition: required and optional field tags.
#[derive(Debug, Clone)]
pub struct MessageDef {
    /// MsgType value (e.g. `"D"`).
    pub msg_type: String,
    /// Message name (e.g. `"NewOrderSingle"`).
    pub name: String,
    /// Required body field tags.
    pub required: Vec<u32>,
    /// Optional body field tags.
    pub optional: Vec<u32>,
}

impl MessageDef {
    /// Whether `tag` is a defined body field of this message.
    pub fn allows_tag(&self, tag: u32) -> bool {
        self.required.contains(&tag) || self.optional.contains(&tag)
    }
}

/// A parsed FIX data dictionary for one version.
#[derive(Debug, Clone)]
pub struct DataDictionary {
    pub(crate) version: String,
    pub(crate) fields: BTreeMap<u32, FieldDef>,
    pub(crate) field_by_name: BTreeMap<String, u32>,
    pub(crate) messages: BTreeMap<String, MessageDef>,
    pub(crate) header: BTreeSet<u32>,
    pub(crate) trailer: BTreeSet<u32>,
    pub(crate) hash: u64,
}

impl DataDictionary {
    /// The dictionary version (BeginString).
    pub fn version(&self) -> &str {
        &self.version
    }

    /// The content hash of the source this dictionary was parsed from.
    pub fn hash(&self) -> u64 {
        self.hash
    }

    /// Look up a field definition by tag.
    pub fn field(&self, tag: u32) -> Option<&FieldDef> {
        self.fields.get(&tag)
    }

    /// Look up a field's tag by name.
    pub fn field_by_name(&self, name: &str) -> Option<u32> {
        self.field_by_name.get(name).copied()
    }

    /// Look up a message definition by MsgType.
    pub fn message(&self, msg_type: &str) -> Option<&MessageDef> {
        self.messages.get(msg_type)
    }

    /// Whether `tag` is a header field.
    pub fn is_header(&self, tag: u32) -> bool {
        self.header.contains(&tag)
    }

    /// Whether `tag` is a trailer field.
    pub fn is_trailer(&self, tag: u32) -> bool {
        self.trailer.contains(&tag)
    }

    /// Number of defined fields.
    pub fn field_count(&self) -> usize {
        self.fields.len()
    }

    /// Number of defined messages.
    pub fn message_count(&self) -> usize {
        self.messages.len()
    }
}

/// FIX SessionRejectReason / business reject reason for a validation failure.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RejectReason {
    /// Tag number is not defined in the dictionary (0).
    InvalidTagNumber,
    /// A required tag is missing (1).
    RequiredTagMissing,
    /// Tag not defined for this message type (2).
    TagNotDefinedForMessageType,
    /// Undefined tag (3).
    UndefinedTag,
    /// Tag specified without a value (4).
    TagSpecifiedWithoutValue,
    /// Value is incorrect / out of range for the field (5).
    ValueIsIncorrect,
    /// Incorrect data format for the value (6).
    IncorrectDataFormat,
    /// Invalid or unsupported MsgType (11).
    InvalidMsgType,
}

impl RejectReason {
    /// The numeric SessionRejectReason (tag 373) code.
    pub fn code(self) -> u32 {
        match self {
            Self::InvalidTagNumber => 0,
            Self::RequiredTagMissing => 1,
            Self::TagNotDefinedForMessageType => 2,
            Self::UndefinedTag => 3,
            Self::TagSpecifiedWithoutValue => 4,
            Self::ValueIsIncorrect => 5,
            Self::IncorrectDataFormat => 6,
            Self::InvalidMsgType => 11,
        }
    }
}

/// A validation failure.
#[derive(Debug, Clone, PartialEq, Eq, thiserror::Error)]
#[error("{reason:?} (tag {ref_tag:?}): {text}")]
pub struct ValidationError {
    /// Why the message was rejected.
    pub reason: RejectReason,
    /// The offending tag, if applicable.
    pub ref_tag: Option<u32>,
    /// `true` => business-level reject; `false` => session-level reject.
    pub business: bool,
    /// Human-readable detail.
    pub text: String,
}

impl ValidationError {
    pub(crate) fn session(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: false,
            text: text.to_owned(),
        }
    }

    pub(crate) fn business(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: true,
            text: text.to_owned(),
        }
    }
}

/// Which validation checks to apply (maps to the FIX `Validate*` config toggles).
#[derive(Debug, Clone, Copy)]
pub struct ValidationOptions {
    /// Reject fields present with an empty value.
    pub validate_fields_have_values: bool,
    /// Validate user-defined fields (tags ≥ 5000) rather than skipping them.
    pub validate_user_defined_fields: bool,
    /// Permit fields not defined for the message type / dictionary.
    pub allow_unknown_msg_fields: bool,
    /// Check that required fields are present.
    pub check_required_fields: bool,
    /// Check field value formats and enumerations.
    pub check_field_types: bool,
}

impl Default for ValidationOptions {
    fn default() -> Self {
        Self {
            validate_fields_have_values: true,
            validate_user_defined_fields: false,
            allow_unknown_msg_fields: false,
            check_required_fields: true,
            check_field_types: true,
        }
    }
}

//! Message construction contract.

use crate::message::Message;

/// Constructs empty messages for a given protocol version and message type.
///
/// The dictionary-backed implementation (typed messages) arrives in `truefix-dict`
/// (Stage S4); this is the core contract skeleton.
pub trait MessageFactory {
    /// Create an empty message for `begin_string` (e.g. `"FIX.4.4"`) and `msg_type`.
    fn create(&self, begin_string: &str, msg_type: &str) -> Message;
}

//! SQL-backed message store (JDBC-equivalent), behind the `sql` feature.

use std::str::FromStr;

use async_trait::async_trait;
use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use sqlx::Row;

use crate::{MessageStore, StoreError};

fn backend<E: std::fmt::Display>(e: E) -> StoreError {
    StoreError::Backend(e.to_string())
}

/// A SQL-backed store using `sqlx` (SQLite). Maps the QuickFIX/J JDBC store tables
/// (sequence numbers + sent messages) to a relational schema.
pub struct SqlStore {
    pool: SqlitePool,
}

impl SqlStore {
    /// Connect to `url` (e.g. `sqlite://truefix.db` or `sqlite::memory:`) and ensure the schema.
    pub async fn connect(url: &str) -> Result<Self, StoreError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(backend)?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts).await.map_err(backend)?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS seqnums (\
             id INTEGER PRIMARY KEY CHECK (id = 0), sender INTEGER NOT NULL, target INTEGER NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;
        sqlx::query("INSERT OR IGNORE INTO seqnums (id, sender, target) VALUES (0, 1, 1)")
            .execute(&pool)
            .await
            .map_err(backend)?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS messages (seq INTEGER PRIMARY KEY, data BLOB NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;

        Ok(Self { pool })
    }

    async fn get_seq(&self, column: &str) -> Result<u64, StoreError> {
        let sql = format!("SELECT {column} FROM seqnums WHERE id = 0");
        let row = sqlx::query(&sql)
            .fetch_one(&self.pool)
            .await
            .map_err(backend)?;
        let value: i64 = row.try_get(column).map_err(backend)?;
        Ok(value as u64)
    }

    async fn set_seq(&self, column: &str, seq: u64) -> Result<(), StoreError> {
        let sql = format!("UPDATE seqnums SET {column} = ? WHERE id = 0");
        sqlx::query(&sql)
            .bind(seq as i64)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

#[async_trait]
impl MessageStore for SqlStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("sender").await
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("target").await
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("sender", seq).await
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("target", seq).await
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        sqlx::query("INSERT OR REPLACE INTO messages (seq, data) VALUES (?, ?)")
            .bind(seq as i64)
            .bind(message)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        let rows =
            sqlx::query("SELECT seq, data FROM messages WHERE seq BETWEEN ? AND ? ORDER BY seq")
                .bind(begin as i64)
                .bind(end as i64)
                .fetch_all(&self.pool)
                .await
                .map_err(backend)?;
        let mut out = Vec::with_capacity(rows.len());
        for row in rows {
            let seq: i64 = row.try_get("seq").map_err(backend)?;
            let data: Vec<u8> = row.try_get("data").map_err(backend)?;
            out.push((seq as u64, data));
        }
        Ok(out)
    }
    async fn reset(&self) -> Result<(), StoreError> {
        sqlx::query("DELETE FROM messages")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        sqlx::query("UPDATE seqnums SET sender = 1, target = 1 WHERE id = 0")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

//! SQL-backed log (JDBC-equivalent), behind the `sql` feature.
//!
//! The [`Log`] trait is synchronous and infallible, while `sqlx` is async. [`SqlLog`] bridges the
//! two: each entry is pushed onto an unbounded channel (a non-blocking, sync send) and written to
//! the database by a background task.

use std::str::FromStr;

use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use tokio::sync::mpsc;

use crate::{Log, LogError};

enum Entry {
    Message {
        direction: &'static str,
        text: String,
    },
    Event {
        text: String,
    },
}

/// A SQL-backed log writing to `log_messages` and `log_events` tables via a background task.
pub struct SqlLog {
    tx: mpsc::UnboundedSender<Entry>,
}

impl SqlLog {
    /// Connect to `url` (e.g. `sqlite://truefix-log.db`), ensure the schema, and spawn the writer.
    pub async fn connect(url: &str) -> Result<Self, LogError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(|e| LogError::Io(e.to_string()))?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts)
            .await
            .map_err(|e| LogError::Io(e.to_string()))?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             direction TEXT NOT NULL, text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_events (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;

        let (tx, mut rx) = mpsc::unbounded_channel::<Entry>();
        tokio::spawn(async move {
            while let Some(entry) = rx.recv().await {
                match entry {
                    Entry::Message { direction, text } => {
                        let _ =
                            sqlx::query("INSERT INTO log_messages (direction, text) VALUES (?, ?)")
                                .bind(direction)
                                .bind(text)
                                .execute(&pool)
                                .await;
                    }
                    Entry::Event { text } => {
                        let _ = sqlx::query("INSERT INTO log_events (text) VALUES (?)")
                            .bind(text)
                            .execute(&pool)
                            .await;
                    }
                }
            }
        });

        Ok(Self { tx })
    }
}

impl Log for SqlLog {
    fn on_incoming(&self, message: &str) {
        let _ = self.tx.send(Entry::Message {
            direction: "I",
            text: message.to_owned(),
        });
    }
    fn on_outgoing(&self, message: &str) {
        let _ = self.tx.send(Entry::Message {
            direction: "O",
            text: message.to_owned(),
        });
    }
    fn on_event(&self, text: &str) {
        let _ = self.tx.send(Entry::Event {
            text: text.to_owned(),
        });
    }
}

//! Session scheduling: when a session should be active.
//!
//! Supports 24×7 (NonStopSession), daily windows (StartTime/EndTime), a weekday filter, and a
//! fixed UTC offset (TimeZone, simplified to a whole-second offset). Named time zones and full
//! weekly StartDay/EndDay windows can extend this later.

use time::{OffsetDateTime, Time, UtcOffset, Weekday};

/// A session activity schedule.
#[derive(Debug, Clone, Default)]
pub struct Schedule {
    /// Always in session (24×7).
    pub non_stop: bool,
    /// Daily window start (local time), if any.
    pub start_time: Option<Time>,
    /// Daily window end (local time), if any.
    pub end_time: Option<Time>,
    /// Allowed weekdays; `None` means every day.
    pub weekdays: Option<Vec<Weekday>>,
    /// Local time-zone offset from UTC, in whole seconds.
    pub utc_offset_seconds: i32,
}

impl Schedule {
    /// A 24×7 schedule.
    pub fn non_stop() -> Self {
        Self {
            non_stop: true,
            ..Self::default()
        }
    }

    /// A daily window `[start, end)` in local time (wraps past midnight if `end < start`).
    pub fn daily(start: Time, end: Time) -> Self {
        Self {
            start_time: Some(start),
            end_time: Some(end),
            ..Self::default()
        }
    }

    /// Restrict to the given weekdays.
    pub fn with_weekdays(mut self, days: Vec<Weekday>) -> Self {
        self.weekdays = Some(days);
        self
    }

    /// Set the local UTC offset in whole seconds.
    pub fn with_utc_offset_seconds(mut self, seconds: i32) -> Self {
        self.utc_offset_seconds = seconds;
        self
    }

    /// Whether `now_utc` falls within the schedule.
    pub fn is_in_session(&self, now_utc: OffsetDateTime) -> bool {
        if self.non_stop {
            return true;
        }
        let offset =
            UtcOffset::from_whole_seconds(self.utc_offset_seconds).unwrap_or(UtcOffset::UTC);
        let local = now_utc.to_offset(offset);
        if let Some(days) = &self.weekdays {
            if !days.contains(&local.weekday()) {
                return false;
            }
        }
        match (self.start_time, self.end_time) {
            (Some(start), Some(end)) => in_window(local.time(), start, end),
            _ => true,
        }
    }
}

fn in_window(t: Time, start: Time, end: Time) -> bool {
    if start <= end {
        t >= start && t < end
    } else {
        // window wraps past midnight
        t >= start || t < end
    }
}

//! UTC SendingTime formatting.

use time::OffsetDateTime;

/// Format the current UTC time as a FIX UTCTimestamp `YYYYMMDD-HH:MM:SS.sss` (millisecond
/// precision). Never panics.
pub(crate) fn now_utc_timestamp() -> String {
    format_utc_timestamp(OffsetDateTime::now_utc())
}

fn format_utc_timestamp(dt: OffsetDateTime) -> String {
    let ms = dt.millisecond();
    format!(
        "{:04}{:02}{:02}-{:02}:{:02}:{:02}.{:03}",
        dt.year(),
        u8::from(dt.month()),
        dt.day(),
        dt.hour(),
        dt.minute(),
        dt.second(),
        ms
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn format_has_expected_shape() {
        let s = now_utc_timestamp();
        // YYYYMMDD-HH:MM:SS.mmm => 21 chars
        assert_eq!(s.len(), 21, "{s}");
        assert_eq!(s.as_bytes().get(8), Some(&b'-'));
    }
}

//! Runtime message validation against a [`DataDictionary`].

use truefix_core::Message;

use crate::model::{DataDictionary, RejectReason, ValidationError, ValidationOptions};

/// The first user-defined-field tag (UDFs occupy 5000–9999 in FIX).
const UDF_START: u32 = 5000;

impl DataDictionary {
    /// Validate `message` against this dictionary using `opts`.
    ///
    /// Returns the first failure found. Field-membership/format/required failures are
    /// session-level rejects; an unknown-but-structural MsgType is a business-level reject
    /// (FR-C4 two rejection layers).
    pub fn validate(
        &self,
        message: &Message,
        opts: &ValidationOptions,
    ) -> Result<(), ValidationError> {
        let msg_type = message.msg_type().ok_or_else(|| {
            ValidationError::session(RejectReason::InvalidMsgType, Some(35), "missing MsgType")
        })?;
        let mdef = self.message(msg_type).ok_or_else(|| {
            ValidationError::business(
                RejectReason::InvalidMsgType,
                Some(35),
                "MsgType not defined in dictionary",
            )
        })?;

        for field in message
            .header
            .fields()
            .chain(message.body.fields())
            .chain(message.trailer.fields())
        {
            let tag = field.tag();

            if opts.validate_fields_have_values && field.value_bytes().is_empty() {
                return Err(ValidationError::session(
                    RejectReason::TagSpecifiedWithoutValue,
                    Some(tag),
                    "field has no value",
                ));
            }

            match self.field(tag) {
                None => {
                    let is_udf = tag >= UDF_START;
                    if is_udf && !opts.validate_user_defined_fields {
                        continue;
                    }
                    if opts.allow_unknown_msg_fields {
                        continue;
                    }
                    return Err(ValidationError::session(
                        RejectReason::InvalidTagNumber,
                        Some(tag),
                        "tag not defined in dictionary",
                    ));
                }
                Some(fdef) => {
                    if opts.check_field_types {
                        if !fdef.field_type.value_ok(field) {
                            return Err(ValidationError::session(
                                RejectReason::IncorrectDataFormat,
                                Some(tag),
                                "value has incorrect data format",
                            ));
                        }
                        if let Ok(value) = field.as_str() {
                            if !fdef.allows(value) {
                                return Err(ValidationError::session(
                                    RejectReason::ValueIsIncorrect,
                                    Some(tag),
                                    "value is not an allowed enumeration",
                                ));
                            }
                        }
                    }

                    let belongs =
                        self.is_header(tag) || self.is_trailer(tag) || mdef.allows_tag(tag);
                    if !belongs && !opts.allow_unknown_msg_fields {
                        return Err(ValidationError::session(
                            RejectReason::TagNotDefinedForMessageType,
                            Some(tag),
                            "tag not defined for this message type",
                        ));
                    }
                }
            }
        }

        if opts.check_required_fields {
            for &tag in &mdef.required {
                if !present(message, tag) {
                    return Err(ValidationError::session(
                        RejectReason::RequiredTagMissing,
                        Some(tag),
                        "required field missing",
                    ));
                }
            }
        }

        Ok(())
    }
}

fn present(message: &Message, tag: u32) -> bool {
    message.header.get(tag).is_some()
        || message.body.get(tag).is_some()
        || message.trailer.get(tag).is_some()
}

//! The AT scenario model and runner.

use std::net::SocketAddr;
use std::sync::Arc;
use std::time::Duration;

use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::net::TcpStream;
use tokio::task::JoinHandle;
use tokio::time::timeout;

use truefix_core::{decode, frame_length, Field, Message};
use truefix_session::{Application, Role, SessionConfig, SessionId};
use truefix_transport::AcceptorBuilder;

/// A message the scenario expects the server to send: a MsgType plus required field matches.
/// Volatile fields (SendingTime, BodyLength, CheckSum) are intentionally not matched.
#[derive(Debug, Clone)]
pub struct ExpectMsg {
    /// Expected MsgType (tag 35).
    pub msg_type: String,
    /// `(tag, value)` pairs that must be present (in header or body) with the given value.
    pub fields: Vec<(u32, String)>,
}

impl ExpectMsg {
    /// Expect a message of `msg_type` with no specific field requirements.
    pub fn of(msg_type: &str) -> Self {
        Self {
            msg_type: msg_type.to_owned(),
            fields: Vec::new(),
        }
    }

    /// Require a field value.
    #[must_use]
    pub fn field(mut self, tag: u32, value: &str) -> Self {
        self.fields.push((tag, value.to_owned()));
        self
    }
}

/// A single scenario step.
#[derive(Debug, Clone)]
pub enum Step {
    /// Send a message to the server.
    Send(Message),
    /// Expect a matching message from the server.
    Expect(ExpectMsg),
    /// Expect the server to disconnect (no further message).
    ExpectDisconnect,
}

/// A scripted acceptance-test scenario.
#[derive(Debug, Clone)]
pub struct Scenario {
    /// Scenario name (matches the QuickFIX AT scenario it reproduces).
    pub name: String,
    /// FIX versions this scenario targets.
    pub versions: Vec<String>,
    /// The scripted steps.
    pub steps: Vec<Step>,
}

/// The result of running one scenario against one version.
#[derive(Debug, Clone)]
pub struct ScenarioResult {
    /// Scenario name.
    pub name: String,
    /// FIX version.
    pub version: String,
    /// `Ok` on pass, `Err(reason)` on failure.
    pub outcome: Result<(), String>,
}

/// Start a black-box acceptor that serves any session via a dynamic template for `version`.
/// Returns the bound address and the accept-loop join handle.
pub async fn start_acceptor(version: &str) -> std::io::Result<(SocketAddr, JoinHandle<()>)> {
    struct PassiveApp;
    #[async_trait::async_trait]
    impl Application for PassiveApp {
        async fn on_logon(&self, _s: &SessionId) {}
    }

    let mut template = SessionConfig::new(version, "SERVER", "CLIENT", Role::Acceptor);
    template.heartbeat_interval = 30;
    template.check_latency = false; // scenarios use fixed timestamps

    // Enable dictionary validation so field-level reject scenarios produce Reject messages.
    let validator = match version {
        "FIX.4.2" => truefix_dict::load_fix42().ok(),
        "FIX.4.4" => truefix_dict::load_fix44().ok(),
        _ => None,
    }
    .map(|dict| (dict, truefix_dict::ValidationOptions::default()));
    let services = truefix_transport::Services {
        validator,
        ..truefix_transport::Services::default()
    };

    let acceptor = AcceptorBuilder::bind(
        "127.0.0.1:0".parse().unwrap_or_else(|_| unreachable_addr()),
        Arc::new(PassiveApp),
    )
    .await?
    .with_dynamic_template(template)
    .with_services(services);
    let addr = acceptor.local_addr()?;
    let handle = acceptor.serve();
    Ok((addr, handle))
}

fn unreachable_addr() -> SocketAddr {
    SocketAddr::from(([127, 0, 0, 1], 0))
}

/// Run one scenario against an already-started acceptor at `addr`.
pub async fn run_scenario(scenario: &Scenario, addr: SocketAddr) -> Result<(), String> {
    let mut stream = TcpStream::connect(addr)
        .await
        .map_err(|e| format!("connect: {e}"))?;
    let mut buf: Vec<u8> = Vec::new();

    for (i, step) in scenario.steps.iter().enumerate() {
        match step {
            Step::Send(msg) => {
                stream
                    .write_all(&msg.encode())
                    .await
                    .map_err(|e| format!("step {i}: send: {e}"))?;
            }
            Step::Expect(expect) => {
                let msg = read_message(&mut stream, &mut buf, Duration::from_secs(2))
                    .await
                    .ok_or_else(|| {
                        format!("step {i}: expected {} but got nothing", expect.msg_type)
                    })?;
                check_match(&msg, expect).map_err(|e| format!("step {i}: {e}"))?;
            }
            Step::ExpectDisconnect => {
                if read_message(&mut stream, &mut buf, Duration::from_secs(2))
                    .await
                    .is_some()
                {
                    return Err(format!("step {i}: expected disconnect but got a message"));
                }
            }
        }
    }
    Ok(())
}

/// Run the full matrix (each scenario against each of its target versions), starting a fresh
/// acceptor per version. Returns one [`ScenarioResult`] per (scenario, version).
pub async fn run_report(scenarios: &[Scenario]) -> Vec<ScenarioResult> {
    let mut results = Vec::new();
    // Collect the set of versions referenced.
    let mut versions: Vec<String> = Vec::new();
    for s in scenarios {
        for v in &s.versions {
            if !versions.contains(v) {
                versions.push(v.clone());
            }
        }
    }

    for version in &versions {
        let Ok((addr, handle)) = start_acceptor(version).await else {
            for s in scenarios.iter().filter(|s| s.versions.contains(version)) {
                results.push(ScenarioResult {
                    name: s.name.clone(),
                    version: version.clone(),
                    outcome: Err("could not start acceptor".to_owned()),
                });
            }
            continue;
        };
        for s in scenarios.iter().filter(|s| s.versions.contains(version)) {
            let outcome = run_scenario(s, addr).await;
            results.push(ScenarioResult {
                name: s.name.clone(),
                version: version.clone(),
                outcome,
            });
        }
        handle.abort();
    }
    results
}

fn check_match(msg: &Message, expect: &ExpectMsg) -> Result<(), String> {
    if msg.msg_type() != Some(expect.msg_type.as_str()) {
        return Err(format!(
            "expected MsgType {:?}, got {:?}",
            expect.msg_type,
            msg.msg_type()
        ));
    }
    for (tag, want) in &expect.fields {
        let got = field_value(msg, *tag);
        if got.as_deref() != Some(want.as_str()) {
            return Err(format!("tag {tag}: expected {want:?}, got {got:?}"));
        }
    }
    Ok(())
}

fn field_value(msg: &Message, tag: u32) -> Option<String> {
    let field = msg
        .header
        .get(tag)
        .or_else(|| msg.body.get(tag))
        .or_else(|| msg.trailer.get(tag))?;
    field.as_str().ok().map(str::to_owned)
}

async fn read_message(
    stream: &mut TcpStream,
    buf: &mut Vec<u8>,
    wait: Duration,
) -> Option<Message> {
    loop {
        if let Ok(Some(total)) = frame_length(buf) {
            let raw: Vec<u8> = buf.drain(..total).collect();
            return decode(&raw).ok();
        }
        let mut chunk = [0u8; 4096];
        match timeout(wait, stream.read(&mut chunk)).await {
            Ok(Ok(0)) | Ok(Err(_)) | Err(_) => return None,
            Ok(Ok(n)) => {
                if let Some(slice) = chunk.get(..n) {
                    buf.extend_from_slice(slice);
                }
            }
        }
    }
}

/// Helper to build a client-side message with the standard header.
pub fn client_message(version: &str, msg_type: &str, seq: i64) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(8, version));
    m.header.set(Field::string(35, msg_type));
    m.header.set(Field::int(34, seq));
    m.header.set(Field::string(49, "CLIENT"));
    m.header.set(Field::string(56, "SERVER"));
    m.header.set(Field::string(52, "20240101-00:00:00"));
    m
}

//! The sans-IO session state machine.
//!
//! The engine consumes [`Event`]s and returns [`Action`]s, performing no I/O itself, so it is
//! deterministic and unit-testable; the transport drives it. Stage S3 adds inbound sequence
//! validation, an in-memory store of sent messages, ResendRequest/SequenceReset handling
//! (gap fill, PossDup/OrigSendingTime), chunked resend, ResetSeqNumFlag, and NextExpectedMsgSeqNum.
//! Persistence beyond memory and scheduling arrive in later stages.

use core::cmp::Ordering;
use std::collections::BTreeMap;

use truefix_core::{Field, Message};
use truefix_dict::{DataDictionary, ValidationOptions};

use crate::admin;
use crate::config::{Role, SessionConfig};
use crate::session_id::SessionId;
use crate::tags::{
    GAP_FILL_FLAG, HEART_BT_INT, MSG_SEQ_NUM, NEW_SEQ_NO, NEXT_EXPECTED_MSG_SEQ_NUM, POSS_DUP_FLAG,
    RESET_SEQ_NUM_FLAG,
};
use crate::time_util::now_utc_timestamp;

/// Session lifecycle state.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SessionState {
    /// Not connected / logged out.
    Disconnected,
    /// Logon sent or awaited; not yet logged on.
    AwaitingLogon,
    /// Fully logged on.
    LoggedOn,
    /// Logout initiated; awaiting the counterparty's Logout.
    AwaitingLogout,
}

/// An input to the engine.
#[derive(Debug)]
pub enum Event {
    /// The transport connection is established.
    Connected,
    /// An inbound message was decoded.
    Received(Message),
    /// A periodic (≈1 second) timer tick.
    Tick,
    /// The application requested a graceful logout.
    StartLogout,
}

/// A point-in-time snapshot of a session, for monitoring (FR-L1).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct SessionStatus {
    /// Lifecycle state.
    pub state: SessionState,
    /// Whether the session is logged on.
    pub logged_on: bool,
    /// Next outbound sequence number.
    pub next_sender_seq: u64,
    /// Next inbound sequence number expected.
    pub next_target_seq: u64,
}

/// An output from the engine for the transport to perform.
#[derive(Debug)]
pub enum Action {
    /// Send this message to the counterparty.
    Send(Message),
    /// Close the connection.
    Disconnect,
}

/// A single FIX session.
pub struct Session {
    config: SessionConfig,
    id: SessionId,
    state: SessionState,
    next_out_seq: u64,
    next_in_seq: u64,
    ticks_since_send: u32,
    ticks_since_recv: u32,
    ticks_awaiting: u32,
    test_request_outstanding: bool,
    logon_sent: bool,
    resend_requested: bool,
    /// Sent messages, by sequence number, for resend.
    store: BTreeMap<u64, Message>,
    /// Received out-of-order messages (seq > expected), awaiting gap fill.
    queue: BTreeMap<u64, Message>,
    /// Optional inbound application-message validator (dictionary + toggles).
    validator: Option<(DataDictionary, ValidationOptions)>,
}

impl Session {
    /// Create a new session in the `Disconnected` state.
    pub fn new(config: SessionConfig) -> Self {
        let id = config.session_id();
        Self {
            config,
            id,
            state: SessionState::Disconnected,
            next_out_seq: 1,
            next_in_seq: 1,
            ticks_since_send: 0,
            ticks_since_recv: 0,
            ticks_awaiting: 0,
            test_request_outstanding: false,
            logon_sent: false,
            resend_requested: false,
            store: BTreeMap::new(),
            queue: BTreeMap::new(),
            validator: None,
        }
    }

    /// Enable inbound application-message validation against `dict` using `opts`. Admin messages
    /// are not validated here. Invalid messages produce a Reject (session-level) or
    /// BusinessMessageReject (business-level) instead of being delivered.
    pub fn set_dictionary(&mut self, dict: DataDictionary, opts: ValidationOptions) {
        self.validator = Some((dict, opts));
    }

    /// The session's identity.
    pub fn id(&self) -> &SessionId {
        &self.id
    }

    /// The current state.
    pub fn state(&self) -> SessionState {
        self.state
    }

    /// Whether the session is logged on.
    pub fn is_logged_on(&self) -> bool {
        self.state == SessionState::LoggedOn
    }

    /// The next outbound sequence number that will be used.
    pub fn next_out_seq(&self) -> u64 {
        self.next_out_seq
    }

    /// The next inbound sequence number expected.
    pub fn next_in_seq(&self) -> u64 {
        self.next_in_seq
    }

    /// Seed the sequence numbers from a persistent store (call before [`Event::Connected`]).
    /// Has no effect once a logon has been sent.
    pub fn seed_sequences(&mut self, next_out: u64, next_in: u64) {
        if !self.logon_sent {
            self.next_out_seq = next_out.max(1);
            self.next_in_seq = next_in.max(1);
        }
    }

    /// A monitoring snapshot of the session (FR-L1).
    pub fn status(&self) -> SessionStatus {
        SessionStatus {
            state: self.state,
            logged_on: self.is_logged_on(),
            next_sender_seq: self.next_out_seq,
            next_target_seq: self.next_in_seq,
        }
    }

    /// Operational reset: clear stored messages and set both sequence numbers back to 1 (FR-L2).
    pub fn reset(&mut self) {
        self.reset_sequences(true);
        self.logon_sent = false;
    }

    /// Drive the engine with an [`Event`], producing [`Action`]s.
    pub fn handle(&mut self, event: Event) -> Vec<Action> {
        match event {
            Event::Connected => self.on_connected(),
            Event::Received(msg) => self.on_received(msg),
            Event::Tick => self.on_tick(),
            Event::StartLogout => self.on_start_logout(),
        }
    }

    /// Send an application message: stamps the header (seq, comp IDs, SendingTime), stores it for
    /// possible resend, and returns the send action.
    pub fn send_app(&mut self, mut msg: Message) -> Vec<Action> {
        let seq = self.next_seq();
        msg.header.set(Field::string(8, &self.config.begin_string));
        msg.header
            .set(Field::string(49, &self.config.sender_comp_id));
        msg.header
            .set(Field::string(56, &self.config.target_comp_id));
        msg.header.set(Field::int(MSG_SEQ_NUM, seq as i64));
        msg.header.set(Field::string(52, &now_utc_timestamp()));
        vec![self.send_stored(msg)]
    }

    fn hb(&self) -> u32 {
        self.config.heartbeat_interval.max(1)
    }

    fn next_seq(&mut self) -> u64 {
        let s = self.next_out_seq;
        self.next_out_seq = self.next_out_seq.saturating_add(1);
        s
    }

    /// Send a normally-sequenced message: store it by its MsgSeqNum for resend, reset the send
    /// timer.
    fn send_stored(&mut self, mut msg: Message) -> Action {
        self.ticks_since_send = 0;
        if self.config.enable_last_msg_seq_num_processed {
            // LastMsgSeqNumProcessed (369): the last inbound sequence number we have processed.
            let last = self.next_in_seq.saturating_sub(1);
            msg.header.set(Field::int(369, last as i64));
        }
        if let Some(seq) = msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
        {
            self.store.insert(seq as u64, msg.clone());
        }
        Action::Send(msg)
    }

    /// Send without allocating a new sequence number or storing (used for resend responses).
    fn send_raw(&mut self, msg: Message) -> Action {
        self.ticks_since_send = 0;
        Action::Send(msg)
    }

    fn reset_sequences(&mut self, full: bool) {
        self.next_in_seq = 1;
        self.queue.clear();
        self.resend_requested = false;
        if full {
            self.next_out_seq = 1;
            self.store.clear();
        }
    }

    fn latency_ok(&self, msg: &Message) -> bool {
        if !self.config.check_latency {
            return true;
        }
        let Some(field) = msg.header.get(crate::tags::SENDING_TIME) else {
            return true;
        };
        let Ok(ts) = field.as_utc_timestamp() else {
            return true; // unparseable SendingTime is a dictionary/validation concern
        };
        let now = time::OffsetDateTime::now_utc();
        (now - ts).whole_seconds().abs() <= i64::from(self.config.max_latency)
    }

    fn on_connected(&mut self) -> Vec<Action> {
        self.ticks_awaiting = 0;
        self.state = SessionState::AwaitingLogon;
        match self.config.role {
            Role::Initiator => {
                let next_exp = self.maybe_next_expected();
                let seq = self.next_seq();
                let msg = admin::logon(&self.config, seq, next_exp);
                self.logon_sent = true;
                vec![self.send_stored(msg)]
            }
            Role::Acceptor => Vec::new(),
        }
    }

    fn maybe_next_expected(&self) -> Option<u64> {
        if self.config.enable_next_expected_msg_seq_num {
            Some(self.next_in_seq)
        } else {
            None
        }
    }

    fn on_received(&mut self, msg: Message) -> Vec<Action> {
        self.ticks_since_recv = 0;
        self.test_request_outstanding = false;

        // CheckLatency / MaxLatency: a stale SendingTime aborts the session.
        if !self.latency_ok(&msg) {
            let seq = self.next_seq();
            let lo = admin::logout(&self.config, seq, Some("SendingTime accuracy problem"));
            self.state = SessionState::Disconnected;
            return vec![self.send_stored(lo), Action::Disconnect];
        }

        let mt = msg.msg_type().map(str::to_owned);

        if mt.as_deref() == Some("A") {
            return self.on_logon(msg);
        }
        if mt.as_deref() == Some("4") {
            return self.on_sequence_reset(&msg);
        }

        let seq = match msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
        {
            Some(s) => s as u64,
            None => {
                let s = self.next_seq();
                let rej = admin::reject(&self.config, s, 0, "missing or invalid MsgSeqNum");
                return vec![self.send_stored(rej)];
            }
        };
        let poss_dup = msg.header.get(POSS_DUP_FLAG).and_then(|f| f.as_str().ok()) == Some("Y");

        match seq.cmp(&self.next_in_seq) {
            Ordering::Equal => {
                if let Some(reject) = self.validate_app(&msg) {
                    let mut actions = vec![reject];
                    self.next_in_seq = self.next_in_seq.saturating_add(1);
                    actions.extend(self.drain_queue());
                    return actions;
                }
                let mut actions = self.process_in_order(&msg, mt.as_deref());
                self.next_in_seq = self.next_in_seq.saturating_add(1);
                actions.extend(self.drain_queue());
                actions
            }
            Ordering::Greater => {
                self.queue.insert(seq, msg);
                if self.resend_requested {
                    Vec::new()
                } else {
                    self.resend_requested = true;
                    let begin = self.next_in_seq;
                    vec![self.request_resend(begin)]
                }
            }
            Ordering::Less => {
                if poss_dup {
                    Vec::new()
                } else {
                    let s = self.next_seq();
                    let lo = admin::logout(&self.config, s, Some("MsgSeqNum too low"));
                    self.state = SessionState::Disconnected;
                    vec![self.send_stored(lo), Action::Disconnect]
                }
            }
        }
    }

    /// Validate an inbound application message; on failure, return a Reject/BusinessMessageReject
    /// action. Admin messages and the no-dictionary case return `None`.
    fn validate_app(&mut self, msg: &Message) -> Option<Action> {
        let error = {
            let (dict, opts) = self.validator.as_ref()?;
            if is_admin_type(msg.msg_type()) {
                return None;
            }
            dict.validate(msg, opts).err()
        }?;
        let ref_seq = msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
            .map_or(0, |s| s as u64);
        let ref_mt = msg.msg_type().map(str::to_owned);
        let seq = self.next_seq();
        let reject = if error.business {
            admin::business_message_reject(
                &self.config,
                seq,
                ref_seq,
                ref_mt.as_deref(),
                error.reason.code(),
                &error.text,
            )
        } else {
            admin::reject_with_reason(&self.config, seq, ref_seq, error.reason.code(), &error.text)
        };
        Some(self.send_stored(reject))
    }

    fn process_in_order(&mut self, msg: &Message, mt: Option<&str>) -> Vec<Action> {
        match mt {
            Some("1") => self.answer_test_request(msg),
            Some("2") => self.on_resend_request(msg),
            Some("5") => self.on_logout_msg(),
            _ => Vec::new(),
        }
    }

    fn drain_queue(&mut self) -> Vec<Action> {
        let mut actions = Vec::new();
        while let Some(msg) = self.queue.remove(&self.next_in_seq) {
            let mt = msg.msg_type().map(str::to_owned);
            actions.extend(self.process_in_order(&msg, mt.as_deref()));
            self.next_in_seq = self.next_in_seq.saturating_add(1);
        }
        if self.queue.is_empty() {
            self.resend_requested = false;
        }
        actions
    }

    fn request_resend(&mut self, begin: u64) -> Action {
        let chunk = u64::from(self.config.resend_request_chunk_size);
        let end = if chunk > 0 {
            begin + chunk - 1
        } else {
            0 // 0 = to infinity
        };
        let seq = self.next_seq();
        let rr = admin::resend_request(&self.config, seq, begin, end);
        self.send_stored(rr)
    }

    fn on_resend_request(&mut self, msg: &Message) -> Vec<Action> {
        let begin = msg
            .body
            .get(crate::tags::BEGIN_SEQ_NO)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
            .map_or(0, |s| s as u64);
        let end_req = msg
            .body
            .get(crate::tags::END_SEQ_NO)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s >= 0)
            .map_or(0, |s| s as u64);
        let last = self.next_out_seq.saturating_sub(1);
        let end = if end_req == 0 || end_req > last {
            last
        } else {
            end_req
        };
        if begin == 0 || begin > end {
            return Vec::new();
        }
        self.build_resend(begin, end)
    }

    fn build_resend(&mut self, begin: u64, end: u64) -> Vec<Action> {
        let mut actions = Vec::new();
        let mut gap_start: Option<u64> = None;
        let mut seq = begin;
        while seq <= end {
            let stored = self.store.get(&seq).cloned();
            let is_app = stored
                .as_ref()
                .is_some_and(|m| !is_admin_type(m.msg_type()));
            if is_app {
                if let Some(gs) = gap_start.take() {
                    let action = self.gap_fill(gs, seq);
                    actions.push(action);
                }
                if let Some(m) = stored {
                    let resent = admin::prepare_resend(&m);
                    actions.push(self.send_raw(resent));
                }
            } else if gap_start.is_none() {
                gap_start = Some(seq);
            }
            seq = seq.saturating_add(1);
        }
        if let Some(gs) = gap_start.take() {
            let new_seq = end.saturating_add(1);
            let action = self.gap_fill(gs, new_seq);
            actions.push(action);
        }
        actions
    }

    fn gap_fill(&mut self, from_seq: u64, new_seq_no: u64) -> Action {
        let m = admin::sequence_reset(&self.config, from_seq, new_seq_no, true);
        self.send_raw(m)
    }

    fn on_sequence_reset(&mut self, msg: &Message) -> Vec<Action> {
        let gap_fill = msg.body.get(GAP_FILL_FLAG).and_then(|f| f.as_str().ok()) == Some("Y");
        let new_seq = msg
            .body
            .get(NEW_SEQ_NO)
            .and_then(|f| f.as_int().ok())
            .filter(|&n| n > 0)
            .map(|n| n as u64);
        if let Some(ns) = new_seq {
            if gap_fill {
                if ns >= self.next_in_seq {
                    self.next_in_seq = ns;
                }
            } else {
                self.next_in_seq = ns;
            }
        }
        self.drain_queue()
    }

    fn on_logon(&mut self, msg: Message) -> Vec<Action> {
        if msg
            .body
            .get(RESET_SEQ_NUM_FLAG)
            .and_then(|f| f.as_str().ok())
            == Some("Y")
        {
            self.reset_sequences(!self.logon_sent);
        }

        let mut actions = Vec::new();
        match self.config.role {
            Role::Acceptor if self.state == SessionState::AwaitingLogon => {
                if let Some(hbi) = msg
                    .body
                    .get(HEART_BT_INT)
                    .and_then(|f| f.as_int().ok())
                    .filter(|&h| h > 0)
                {
                    self.config.heartbeat_interval = hbi as u32;
                }
                self.state = SessionState::LoggedOn;
                let next_exp = self.maybe_next_expected();
                let seq = self.next_seq();
                let resp = admin::logon(&self.config, seq, next_exp);
                self.logon_sent = true;
                actions.push(self.send_stored(resp));
            }
            Role::Initiator if self.state == SessionState::AwaitingLogon => {
                self.state = SessionState::LoggedOn;
            }
            _ => {}
        }

        // Sequence accounting for the Logon message itself.
        if let Some(seq) = msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
            .map(|s| s as u64)
        {
            match seq.cmp(&self.next_in_seq) {
                Ordering::Equal => {
                    self.next_in_seq = self.next_in_seq.saturating_add(1);
                    actions.extend(self.drain_queue());
                }
                Ordering::Greater => {
                    if !self.resend_requested {
                        self.resend_requested = true;
                        let begin = self.next_in_seq;
                        actions.push(self.request_resend(begin));
                    }
                }
                Ordering::Less => {}
            }
        }

        // NextExpectedMsgSeqNum (789): the peer reports the next sequence number it expects from
        // us. If it is behind our outbound counter, resend the gap directly (avoids a round-trip).
        if let Some(next_expected) = msg
            .body
            .get(NEXT_EXPECTED_MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&n| n > 0)
            .map(|n| n as u64)
        {
            if next_expected < self.next_out_seq {
                let end = self.next_out_seq.saturating_sub(1);
                actions.extend(self.build_resend(next_expected, end));
            }
        }

        actions
    }

    fn answer_test_request(&mut self, msg: &Message) -> Vec<Action> {
        if self.state != SessionState::LoggedOn {
            return Vec::new();
        }
        let id = msg
            .body
            .get(crate::tags::TEST_REQ_ID)
            .and_then(|f| f.as_str().ok())
            .map(str::to_owned);
        let seq = self.next_seq();
        let hb = admin::heartbeat(&self.config, seq, id.as_deref());
        vec![self.send_stored(hb)]
    }

    fn on_logout_msg(&mut self) -> Vec<Action> {
        if self.state == SessionState::AwaitingLogout {
            self.enter_disconnected();
            vec![Action::Disconnect]
        } else {
            let seq = self.next_seq();
            let lo = admin::logout(&self.config, seq, None);
            let send = self.send_stored(lo);
            self.enter_disconnected();
            vec![send, Action::Disconnect]
        }
    }

    fn on_start_logout(&mut self) -> Vec<Action> {
        if self.state == SessionState::LoggedOn {
            let seq = self.next_seq();
            let lo = admin::logout(&self.config, seq, None);
            self.ticks_awaiting = 0;
            self.state = SessionState::AwaitingLogout;
            vec![self.send_stored(lo)]
        } else {
            Vec::new()
        }
    }

    fn enter_disconnected(&mut self) {
        self.state = SessionState::Disconnected;
        if self.config.reset_on_disconnect || self.config.reset_on_logout {
            self.reset_sequences(true);
            self.logon_sent = false;
        }
    }

    fn on_tick(&mut self) -> Vec<Action> {
        self.ticks_since_send = self.ticks_since_send.saturating_add(1);
        self.ticks_since_recv = self.ticks_since_recv.saturating_add(1);
        self.ticks_awaiting = self.ticks_awaiting.saturating_add(1);
        let hb = self.hb();
        let mut actions = Vec::new();
        match self.state {
            SessionState::AwaitingLogon
                if self.ticks_awaiting >= self.config.logon_timeout.max(1) =>
            {
                self.enter_disconnected();
                return vec![Action::Disconnect];
            }
            SessionState::LoggedOn => {
                if self.ticks_since_recv >= 2 * hb + 2 {
                    self.enter_disconnected();
                    return vec![Action::Disconnect];
                }
                if self.ticks_since_recv > hb && !self.test_request_outstanding {
                    let seq = self.next_seq();
                    let tr = admin::test_request(&self.config, seq, "TEST");
                    self.test_request_outstanding = true;
                    actions.push(self.send_stored(tr));
                }
                if self.ticks_since_send >= hb {
                    let seq = self.next_seq();
                    let h = admin::heartbeat(&self.config, seq, None);
                    actions.push(self.send_stored(h));
                }
            }
            SessionState::AwaitingLogout
                if self.ticks_awaiting >= self.config.logout_timeout.max(1) =>
            {
                self.enter_disconnected();
                return vec![Action::Disconnect];
            }
            _ => {}
        }
        actions
    }
}

fn is_admin_type(mt: Option<&str>) -> bool {
    matches!(mt, Some("0" | "1" | "2" | "3" | "4" | "5" | "A"))
}

//! Example order-matching acceptor (simplified): maintains a tiny per-symbol book and, when a
//! crossing order arrives, fills both sides with ExecutionReports. Run with
//! `cargo run -p truefix --example ordermatch`.
//!
//! This is a teaching example of the engine's application hooks, not a production matcher.

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

use truefix_core::{Field, Message};
use truefix_session::{Application, Role, SessionConfig, SessionId};
use truefix_transport::{AcceptorBuilder, Monitor, Services};

#[derive(Clone)]
struct RestingOrder {
    session: SessionId,
    cl_ord_id: String,
}

/// Per-symbol resting orders: `(buys, sells)`.
type Book = HashMap<String, (Vec<RestingOrder>, Vec<RestingOrder>)>;

struct OrderMatch {
    monitor: Monitor,
    book: Mutex<Book>,
}

#[async_trait::async_trait]
impl Application for OrderMatch {
    async fn from_app(&self, message: &Message, id: &SessionId) -> Result<(), String> {
        if message.msg_type() != Some("D") {
            return Ok(());
        }
        let symbol = field(message, 55);
        let side = field(message, 54);
        let cl_ord_id = field(message, 11);

        let opposite = {
            let mut book = self.book.lock().map_err(|_| "book poisoned".to_owned())?;
            let entry = book.entry(symbol.clone()).or_default();
            let (buys, sells) = entry;
            let incoming = RestingOrder {
                session: id.clone(),
                cl_ord_id,
            };
            if side == "1" {
                // buy: match against a resting sell, else rest
                let m = sells.pop();
                if m.is_none() {
                    buys.push(incoming.clone());
                }
                m.map(|s| (incoming, s))
            } else {
                let m = buys.pop();
                if m.is_none() {
                    sells.push(incoming.clone());
                }
                m.map(|b| (incoming, b))
            }
        };

        if let Some((a, b)) = opposite {
            self.monitor
                .send_app(&a.session, fill(&a.cl_ord_id, &symbol))
                .await;
            self.monitor
                .send_app(&b.session, fill(&b.cl_ord_id, &symbol))
                .await;
        }
        Ok(())
    }
}

fn field(msg: &Message, tag: u32) -> String {
    msg.body
        .get(tag)
        .and_then(|f| f.as_str().ok())
        .unwrap_or_default()
        .to_owned()
}

fn fill(cl_ord_id: &str, symbol: &str) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(35, "8")); // ExecutionReport
    m.body.set(Field::string(11, cl_ord_id));
    m.body.set(Field::string(55, symbol));
    m.body.set(Field::string(150, "2")); // ExecType = Filled
    m.body.set(Field::string(39, "2")); // OrdStatus = Filled
    m
}

#[tokio::main]
async fn main() {
    let monitor = Monitor::new();
    let services = Services {
        monitor: Some(monitor.clone()),
        ..Services::default()
    };
    let mut template = SessionConfig::new("FIX.4.4", "MATCH", "CLIENT", Role::Acceptor);
    template.check_latency = false;

    let acceptor = AcceptorBuilder::bind(
        "127.0.0.1:9883".parse().expect("addr"),
        Arc::new(OrderMatch {
            monitor,
            book: Mutex::new(HashMap::new()),
        }),
    )
    .await
    .expect("bind")
    .with_dynamic_template(template)
    .with_services(services);

    println!(
        "ordermatch listening on {}",
        acceptor.local_addr().expect("local_addr")
    );
    let _ = acceptor.serve().await;
}

//! FIXT 1.1 transport/application dictionary separation.
//!
//! Under FIXT 1.1 the session (transport) layer and the application layer use **separate**
//! dictionaries. The application dictionary is selected per-message by ApplVerID, falling back to
//! the session's DefaultApplVerID.

use std::collections::BTreeMap;

use crate::model::DataDictionary;

/// A transport dictionary plus one or more application dictionaries keyed by application version.
#[derive(Debug, Clone)]
pub struct FixtDictionaries {
    transport: DataDictionary,
    applications: BTreeMap<String, DataDictionary>,
    default_appl_ver_id: Option<String>,
}

impl FixtDictionaries {
    /// Create from a transport dictionary; add application dictionaries with
    /// [`with_application`](Self::with_application).
    pub fn new(transport: DataDictionary) -> Self {
        Self {
            transport,
            applications: BTreeMap::new(),
            default_appl_ver_id: None,
        }
    }

    /// Register an application dictionary under an application version id (e.g. `"FIX.5.0"`).
    pub fn with_application(
        mut self,
        appl_ver_id: impl Into<String>,
        dict: DataDictionary,
    ) -> Self {
        self.applications.insert(appl_ver_id.into(), dict);
        self
    }

    /// Set the DefaultApplVerID used when a message does not carry an explicit ApplVerID.
    pub fn with_default_appl_ver_id(mut self, appl_ver_id: impl Into<String>) -> Self {
        self.default_appl_ver_id = Some(appl_ver_id.into());
        self
    }

    /// The transport (session-layer) dictionary.
    pub fn transport(&self) -> &DataDictionary {
        &self.transport
    }

    /// Resolve the application dictionary for an explicit `appl_ver_id`, falling back to the
    /// DefaultApplVerID.
    pub fn application_for(&self, appl_ver_id: Option<&str>) -> Option<&DataDictionary> {
        let key = appl_ver_id.or(self.default_appl_ver_id.as_deref())?;
        self.applications.get(key)
    }
}

//! Builders for session-level admin messages.

use truefix_core::{Field, Message};

use crate::config::SessionConfig;
use crate::tags::{
    BEGIN_SEQ_NO, BUSINESS_REJECT_REASON, ENCRYPT_METHOD, END_SEQ_NO, GAP_FILL_FLAG, HEART_BT_INT,
    NEW_SEQ_NO, NEXT_EXPECTED_MSG_SEQ_NUM, ORIG_SENDING_TIME, POSS_DUP_FLAG, REF_MSG_TYPE,
    REF_SEQ_NUM, RESET_SEQ_NUM_FLAG, SENDING_TIME, SESSION_REJECT_REASON, TEST_REQ_ID, TEXT,
};
use crate::time_util::now_utc_timestamp;

/// Build a message with the standard header (8/35/49/56/34/52).
fn base(config: &SessionConfig, msg_type: &str, seq: u64) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(8, &config.begin_string));
    m.header.set(Field::string(35, msg_type));
    m.header.set(Field::string(49, &config.sender_comp_id));
    m.header.set(Field::string(56, &config.target_comp_id));
    m.header.set(Field::int(34, seq as i64));
    m.header.set(Field::string(52, &now_utc_timestamp()));
    m
}

/// Logon (35=A) with EncryptMethod=0 and HeartBtInt; optional ResetSeqNumFlag and
/// NextExpectedMsgSeqNum (789).
pub(crate) fn logon(config: &SessionConfig, seq: u64, next_expected: Option<u64>) -> Message {
    let mut m = base(config, "A", seq);
    m.body.set(Field::int(ENCRYPT_METHOD, 0));
    m.body.set(Field::int(
        HEART_BT_INT,
        i64::from(config.heartbeat_interval),
    ));
    if config.reset_on_logon {
        m.body.set(Field::string(RESET_SEQ_NUM_FLAG, "Y"));
    }
    if let Some(n) = next_expected {
        m.body.set(Field::int(NEXT_EXPECTED_MSG_SEQ_NUM, n as i64));
    }
    m
}

/// Logout (35=5) with optional Text (58).
pub(crate) fn logout(config: &SessionConfig, seq: u64, text: Option<&str>) -> Message {
    let mut m = base(config, "5", seq);
    if let Some(t) = text {
        m.body.set(Field::string(TEXT, t));
    }
    m
}

/// Heartbeat (35=0), optionally echoing a TestReqID (112).
pub(crate) fn heartbeat(config: &SessionConfig, seq: u64, test_req_id: Option<&str>) -> Message {
    let mut m = base(config, "0", seq);
    if let Some(id) = test_req_id {
        m.body.set(Field::string(TEST_REQ_ID, id));
    }
    m
}

/// TestRequest (35=1) with a TestReqID (112).
pub(crate) fn test_request(config: &SessionConfig, seq: u64, id: &str) -> Message {
    let mut m = base(config, "1", seq);
    m.body.set(Field::string(TEST_REQ_ID, id));
    m
}

/// ResendRequest (35=2) for `[begin, end]` (end `0` means "to infinity").
pub(crate) fn resend_request(config: &SessionConfig, seq: u64, begin: u64, end: u64) -> Message {
    let mut m = base(config, "2", seq);
    m.body.set(Field::int(BEGIN_SEQ_NO, begin as i64));
    m.body.set(Field::int(END_SEQ_NO, end as i64));
    m
}

/// SequenceReset (35=4) with NewSeqNo (36); `gap_fill` sets GapFillFlag (123=Y) and PossDupFlag.
pub(crate) fn sequence_reset(
    config: &SessionConfig,
    seq: u64,
    new_seq_no: u64,
    gap_fill: bool,
) -> Message {
    let mut m = base(config, "4", seq);
    m.body.set(Field::int(NEW_SEQ_NO, new_seq_no as i64));
    if gap_fill {
        m.body.set(Field::string(GAP_FILL_FLAG, "Y"));
        m.header.set(Field::string(POSS_DUP_FLAG, "Y"));
    }
    m
}

/// Session-level Reject (35=3) referencing a sequence number with optional Text.
pub(crate) fn reject(config: &SessionConfig, seq: u64, ref_seq: u64, text: &str) -> Message {
    let mut m = base(config, "3", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Session-level Reject (35=3) with a SessionRejectReason (373).
pub(crate) fn reject_with_reason(
    config: &SessionConfig,
    seq: u64,
    ref_seq: u64,
    reason_code: u32,
    text: &str,
) -> Message {
    let mut m = base(config, "3", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    m.body
        .set(Field::int(SESSION_REJECT_REASON, i64::from(reason_code)));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Business Message Reject (35=j) with RefMsgType (372) and BusinessRejectReason (380).
pub(crate) fn business_message_reject(
    config: &SessionConfig,
    seq: u64,
    ref_seq: u64,
    ref_msg_type: Option<&str>,
    reason_code: u32,
    text: &str,
) -> Message {
    let mut m = base(config, "j", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    if let Some(mt) = ref_msg_type {
        m.body.set(Field::string(REF_MSG_TYPE, mt));
    }
    m.body
        .set(Field::int(BUSINESS_REJECT_REASON, i64::from(reason_code)));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Prepare a stored application message for resend: stamp PossDupFlag (43=Y) and OrigSendingTime
/// (122 = the original SendingTime), and refresh SendingTime (52).
pub(crate) fn prepare_resend(original: &Message) -> Message {
    let mut m = original.clone();
    let orig_sending = m
        .header
        .get(SENDING_TIME)
        .and_then(|f| f.as_str().ok())
        .map(str::to_owned);
    m.header.set(Field::string(POSS_DUP_FLAG, "Y"));
    if let Some(orig) = orig_sending {
        m.header.set(Field::string(ORIG_SENDING_TIME, &orig));
    }
    m.header
        .set(Field::string(SENDING_TIME, &now_utc_timestamp()));
    m
}

//! A FIX message: header, body, and trailer field maps.

use crate::error::DecodeError;
use crate::field_map::FieldMap;
use crate::tags::{BEGIN_STRING, MSG_TYPE};

/// A FIX message split into header, body, and trailer regions.
///
/// Decoding routes session-level header tags and trailer tags to their regions; everything
/// else lands in the body. Encoding always emits the canonical order
/// `8, 9, 35, <rest of header>, <body>, <trailer except 10>, 10`.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct Message {
    /// Header fields (BeginString, BodyLength, MsgType, session fields, ...).
    pub header: FieldMap,
    /// Application/body fields.
    pub body: FieldMap,
    /// Trailer fields (SignatureLength, Signature, CheckSum).
    pub trailer: FieldMap,
}

impl Message {
    /// Create an empty message.
    pub fn new() -> Self {
        Self::default()
    }

    /// The BeginString (tag 8) as a string, if present and valid UTF-8.
    pub fn begin_string(&self) -> Option<&str> {
        self.header.get(BEGIN_STRING).and_then(|f| f.as_str().ok())
    }

    /// The MsgType (tag 35) as a string, if present and valid UTF-8.
    pub fn msg_type(&self) -> Option<&str> {
        self.header.get(MSG_TYPE).and_then(|f| f.as_str().ok())
    }

    /// Encode to wire bytes (computes BodyLength and CheckSum).
    pub fn encode(&self) -> Vec<u8> {
        crate::codec::encode(self)
    }

    /// Decode from wire bytes (verifies BodyLength and CheckSum).
    pub fn decode(bytes: &[u8]) -> Result<Self, DecodeError> {
        crate::codec::decode(bytes)
    }
}

//! FIX fields and their typed value converters.

use rust_decimal::Decimal;
use time::OffsetDateTime;

use crate::error::FieldError;

/// A single FIX field: a tag number and its raw (wire) value bytes.
///
/// Raw bytes are preserved verbatim so re-encoding reproduces the original representation
/// (round-trip fidelity, FR-B9). Typed accessors convert on demand and never panic.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Field {
    tag: u32,
    value: Vec<u8>,
}

impl Field {
    /// Create a field from a tag and raw value bytes.
    pub fn new(tag: u32, value: impl Into<Vec<u8>>) -> Self {
        Self {
            tag,
            value: value.into(),
        }
    }

    /// Create a field from a tag and a string value.
    pub fn string(tag: u32, value: &str) -> Self {
        Self::new(tag, value.as_bytes().to_vec())
    }

    /// Create an integer-valued field.
    pub fn int(tag: u32, value: i64) -> Self {
        Self::new(tag, value.to_string().into_bytes())
    }

    /// The field's tag number.
    pub fn tag(&self) -> u32 {
        self.tag
    }

    /// The raw value bytes.
    pub fn value_bytes(&self) -> &[u8] {
        &self.value
    }

    /// The value as a UTF-8 string slice.
    pub fn as_str(&self) -> Result<&str, FieldError> {
        core::str::from_utf8(&self.value).map_err(|_| FieldError::NotUtf8 { tag: self.tag })
    }

    /// The value as an integer.
    pub fn as_int(&self) -> Result<i64, FieldError> {
        let s = self.as_str()?;
        s.trim().parse().map_err(|_| FieldError::NotInt {
            tag: self.tag,
            value: s.to_owned(),
        })
    }

    /// The value as a fixed-precision decimal (FIX Price/Qty/Amt).
    pub fn as_decimal(&self) -> Result<Decimal, FieldError> {
        let s = self.as_str()?;
        s.trim().parse().map_err(|_| FieldError::NotDecimal {
            tag: self.tag,
            value: s.to_owned(),
        })
    }

    /// The value as a single character (FIX char).
    pub fn as_char(&self) -> Result<char, FieldError> {
        let s = self.as_str()?;
        let mut chars = s.chars();
        match (chars.next(), chars.next()) {
            (Some(c), None) => Ok(c),
            _ => Err(FieldError::NotChar {
                tag: self.tag,
                value: s.to_owned(),
            }),
        }
    }

    /// The value as a boolean (`Y`/`N`).
    pub fn as_bool(&self) -> Result<bool, FieldError> {
        match self.value.as_slice() {
            b"Y" => Ok(true),
            b"N" => Ok(false),
            _ => Err(FieldError::NotBool {
                tag: self.tag,
                value: String::from_utf8_lossy(&self.value).into_owned(),
            }),
        }
    }

    /// The value as a UTC timestamp. Accepts up to picosecond fractional digits and
    /// truncates to nanosecond resolution (FR-B7).
    pub fn as_utc_timestamp(&self) -> Result<OffsetDateTime, FieldError> {
        let s = self.as_str()?;
        parse_utc_timestamp(s).ok_or_else(|| FieldError::NotTimestamp {
            tag: self.tag,
            value: s.to_owned(),
        })
    }
}

/// Parse `YYYYMMDD-HH:MM:SS[.fraction]` as UTC. Returns `None` on any malformation.
fn parse_utc_timestamp(s: &str) -> Option<OffsetDateTime> {
    let (date, time_part) = s.split_once('-')?;
    if date.len() != 8 {
        return None;
    }
    let year: i32 = date.get(0..4)?.parse().ok()?;
    let month: u8 = date.get(4..6)?.parse().ok()?;
    let day: u8 = date.get(6..8)?.parse().ok()?;

    let (hms, frac) = match time_part.split_once('.') {
        Some((h, f)) => (h, Some(f)),
        None => (time_part, None),
    };
    let mut parts = hms.split(':');
    let hour: u8 = parts.next()?.parse().ok()?;
    let min: u8 = parts.next()?.parse().ok()?;
    let sec: u8 = parts.next()?.parse().ok()?;
    if parts.next().is_some() {
        return None;
    }

    // Accept >= 1 fractional digits up to picosecond; truncate to nanosecond (first 9 digits).
    let nanos: u32 = match frac {
        None => 0,
        Some(f) => {
            if f.is_empty() || !f.bytes().all(|b| b.is_ascii_digit()) {
                return None;
            }
            let mut buf = [b'0'; 9];
            for (slot, digit) in buf.iter_mut().zip(f.bytes()) {
                *slot = digit;
            }
            core::str::from_utf8(&buf).ok()?.parse().ok()?
        }
    };

    let month = time::Month::try_from(month).ok()?;
    let date = time::Date::from_calendar_date(year, month, day).ok()?;
    let time = time::Time::from_hms_nano(hour, min, sec, nanos).ok()?;
    Some(time::PrimitiveDateTime::new(date, time).assume_utc())
}

