//! Example order-matching acceptor (simplified): maintains a tiny per-symbol book and, when a
//! crossing order arrives, fills both sides with ExecutionReports. Run with
//! `cargo run -p truefix --example ordermatch`.
//!
//! This is a teaching example of the engine's application hooks, not a production matcher.

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

use truefix_core::{Field, Message};
use truefix_session::{Application, Role, SessionConfig, SessionId};
use truefix_transport::{AcceptorBuilder, Monitor, Services};

#[derive(Clone)]
struct RestingOrder {
    session: SessionId,
    cl_ord_id: String,
}

/// Per-symbol resting orders: `(buys, sells)`.
type Book = HashMap<String, (Vec<RestingOrder>, Vec<RestingOrder>)>;

struct OrderMatch {
    monitor: Monitor,
    book: Mutex<Book>,
}

#[async_trait::async_trait]
impl Application for OrderMatch {
    async fn from_app(&self, message: &Message, id: &SessionId) -> Result<(), String> {
        if message.msg_type() != Some("D") {
            return Ok(());
        }
        let symbol = field(message, 55);
        let side = field(message, 54);
        let cl_ord_id = field(message, 11);

        let opposite = {
            let mut book = self.book.lock().map_err(|_| "book poisoned".to_owned())?;
            let entry = book.entry(symbol.clone()).or_default();
            let (buys, sells) = entry;
            let incoming = RestingOrder {
                session: id.clone(),
                cl_ord_id,
            };
            if side == "1" {
                // buy: match against a resting sell, else rest
                let m = sells.pop();
                if m.is_none() {
                    buys.push(incoming.clone());
                }
                m.map(|s| (incoming, s))
            } else {
                let m = buys.pop();
                if m.is_none() {
                    sells.push(incoming.clone());
                }
                m.map(|b| (incoming, b))
            }
        };

        if let Some((a, b)) = opposite {
            self.monitor
                .send_app(&a.session, fill(&a.cl_ord_id, &symbol))
                .await;
            self.monitor
                .send_app(&b.session, fill(&b.cl_ord_id, &symbol))
                .await;
        }
        Ok(())
    }
}

fn field(msg: &Message, tag: u32) -> String {
    msg.body
        .get(tag)
        .and_then(|f| f.as_str().ok())
        .unwrap_or_default()
        .to_owned()
}

fn fill(cl_ord_id: &str, symbol: &str) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(35, "8")); // ExecutionReport
    m.body.set(Field::string(11, cl_ord_id));
    m.body.set(Field::string(55, symbol));
    m.body.set(Field::string(150, "2")); // ExecType = Filled
    m.body.set(Field::string(39, "2")); // OrdStatus = Filled
    m
}

#[tokio::main]
async fn main() {
    let monitor = Monitor::new();
    let services = Services {
        monitor: Some(monitor.clone()),
        ..Services::default()
    };
    let mut template = SessionConfig::new("FIX.4.4", "MATCH", "CLIENT", Role::Acceptor);
    template.check_latency = false;

    let acceptor = AcceptorBuilder::bind(
        "127.0.0.1:9883".parse().expect("addr"),
        Arc::new(OrderMatch {
            monitor,
            book: Mutex::new(HashMap::new()),
        }),
    )
    .await
    .expect("bind")
    .with_dynamic_template(template)
    .with_services(services);

    println!(
        "ordermatch listening on {}",
        acceptor.local_addr().expect("local_addr")
    );
    let _ = acceptor.serve().await;
}

//! FIXT 1.1 transport/application dictionary separation.
//!
//! Under FIXT 1.1 the session (transport) layer and the application layer use **separate**
//! dictionaries. The application dictionary is selected per-message by ApplVerID, falling back to
//! the session's DefaultApplVerID.

use std::collections::BTreeMap;

use crate::model::DataDictionary;

/// A transport dictionary plus one or more application dictionaries keyed by application version.
#[derive(Debug, Clone)]
pub struct FixtDictionaries {
    transport: DataDictionary,
    applications: BTreeMap<String, DataDictionary>,
    default_appl_ver_id: Option<String>,
}

impl FixtDictionaries {
    /// Create from a transport dictionary; add application dictionaries with
    /// [`with_application`](Self::with_application).
    pub fn new(transport: DataDictionary) -> Self {
        Self {
            transport,
            applications: BTreeMap::new(),
            default_appl_ver_id: None,
        }
    }

    /// Register an application dictionary under an application version id (e.g. `"FIX.5.0"`).
    pub fn with_application(
        mut self,
        appl_ver_id: impl Into<String>,
        dict: DataDictionary,
    ) -> Self {
        self.applications.insert(appl_ver_id.into(), dict);
        self
    }

    /// Set the DefaultApplVerID used when a message does not carry an explicit ApplVerID.
    pub fn with_default_appl_ver_id(mut self, appl_ver_id: impl Into<String>) -> Self {
        self.default_appl_ver_id = Some(appl_ver_id.into());
        self
    }

    /// The transport (session-layer) dictionary.
    pub fn transport(&self) -> &DataDictionary {
        &self.transport
    }

    /// Resolve the application dictionary for an explicit `appl_ver_id`, falling back to the
    /// DefaultApplVerID.
    pub fn application_for(&self, appl_ver_id: Option<&str>) -> Option<&DataDictionary> {
        let key = appl_ver_id.or(self.default_appl_ver_id.as_deref())?;
        self.applications.get(key)
    }
}

//! Builders for session-level admin messages.

use truefix_core::{Field, Message};

use crate::config::SessionConfig;
use crate::tags::{
    BEGIN_SEQ_NO, BUSINESS_REJECT_REASON, ENCRYPT_METHOD, END_SEQ_NO, GAP_FILL_FLAG, HEART_BT_INT,
    NEW_SEQ_NO, NEXT_EXPECTED_MSG_SEQ_NUM, ORIG_SENDING_TIME, POSS_DUP_FLAG, REF_MSG_TYPE,
    REF_SEQ_NUM, RESET_SEQ_NUM_FLAG, SENDING_TIME, SESSION_REJECT_REASON, TEST_REQ_ID, TEXT,
};
use crate::time_util::now_utc_timestamp;

/// Build a message with the standard header (8/35/49/56/34/52).
fn base(config: &SessionConfig, msg_type: &str, seq: u64) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(8, &config.begin_string));
    m.header.set(Field::string(35, msg_type));
    m.header.set(Field::string(49, &config.sender_comp_id));
    m.header.set(Field::string(56, &config.target_comp_id));
    m.header.set(Field::int(34, seq as i64));
    m.header.set(Field::string(52, &now_utc_timestamp()));
    m
}

/// Logon (35=A) with EncryptMethod=0 and HeartBtInt; optional ResetSeqNumFlag and
/// NextExpectedMsgSeqNum (789).
pub(crate) fn logon(config: &SessionConfig, seq: u64, next_expected: Option<u64>) -> Message {
    let mut m = base(config, "A", seq);
    m.body.set(Field::int(ENCRYPT_METHOD, 0));
    m.body.set(Field::int(
        HEART_BT_INT,
        i64::from(config.heartbeat_interval),
    ));
    if config.reset_on_logon {
        m.body.set(Field::string(RESET_SEQ_NUM_FLAG, "Y"));
    }
    if let Some(n) = next_expected {
        m.body.set(Field::int(NEXT_EXPECTED_MSG_SEQ_NUM, n as i64));
    }
    m
}

/// Logout (35=5) with optional Text (58).
pub(crate) fn logout(config: &SessionConfig, seq: u64, text: Option<&str>) -> Message {
    let mut m = base(config, "5", seq);
    if let Some(t) = text {
        m.body.set(Field::string(TEXT, t));
    }
    m
}

/// Heartbeat (35=0), optionally echoing a TestReqID (112).
pub(crate) fn heartbeat(config: &SessionConfig, seq: u64, test_req_id: Option<&str>) -> Message {
    let mut m = base(config, "0", seq);
    if let Some(id) = test_req_id {
        m.body.set(Field::string(TEST_REQ_ID, id));
    }
    m
}

/// TestRequest (35=1) with a TestReqID (112).
pub(crate) fn test_request(config: &SessionConfig, seq: u64, id: &str) -> Message {
    let mut m = base(config, "1", seq);
    m.body.set(Field::string(TEST_REQ_ID, id));
    m
}

/// ResendRequest (35=2) for `[begin, end]` (end `0` means "to infinity").
pub(crate) fn resend_request(config: &SessionConfig, seq: u64, begin: u64, end: u64) -> Message {
    let mut m = base(config, "2", seq);
    m.body.set(Field::int(BEGIN_SEQ_NO, begin as i64));
    m.body.set(Field::int(END_SEQ_NO, end as i64));
    m
}

/// SequenceReset (35=4) with NewSeqNo (36); `gap_fill` sets GapFillFlag (123=Y) and PossDupFlag.
pub(crate) fn sequence_reset(
    config: &SessionConfig,
    seq: u64,
    new_seq_no: u64,
    gap_fill: bool,
) -> Message {
    let mut m = base(config, "4", seq);
    m.body.set(Field::int(NEW_SEQ_NO, new_seq_no as i64));
    if gap_fill {
        m.body.set(Field::string(GAP_FILL_FLAG, "Y"));
        m.header.set(Field::string(POSS_DUP_FLAG, "Y"));
    }
    m
}

/// Session-level Reject (35=3) referencing a sequence number with optional Text.
pub(crate) fn reject(config: &SessionConfig, seq: u64, ref_seq: u64, text: &str) -> Message {
    let mut m = base(config, "3", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Session-level Reject (35=3) with a SessionRejectReason (373).
pub(crate) fn reject_with_reason(
    config: &SessionConfig,
    seq: u64,
    ref_seq: u64,
    reason_code: u32,
    text: &str,
) -> Message {
    let mut m = base(config, "3", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    m.body
        .set(Field::int(SESSION_REJECT_REASON, i64::from(reason_code)));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Business Message Reject (35=j) with RefMsgType (372) and BusinessRejectReason (380).
pub(crate) fn business_message_reject(
    config: &SessionConfig,
    seq: u64,
    ref_seq: u64,
    ref_msg_type: Option<&str>,
    reason_code: u32,
    text: &str,
) -> Message {
    let mut m = base(config, "j", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    if let Some(mt) = ref_msg_type {
        m.body.set(Field::string(REF_MSG_TYPE, mt));
    }
    m.body
        .set(Field::int(BUSINESS_REJECT_REASON, i64::from(reason_code)));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Prepare a stored application message for resend: stamp PossDupFlag (43=Y) and OrigSendingTime
/// (122 = the original SendingTime), and refresh SendingTime (52).
pub(crate) fn prepare_resend(original: &Message) -> Message {
    let mut m = original.clone();
    let orig_sending = m
        .header
        .get(SENDING_TIME)
        .and_then(|f| f.as_str().ok())
        .map(str::to_owned);
    m.header.set(Field::string(POSS_DUP_FLAG, "Y"));
    if let Some(orig) = orig_sending {
        m.header.set(Field::string(ORIG_SENDING_TIME, &orig));
    }
    m.header
        .set(Field::string(SENDING_TIME, &now_utc_timestamp()));
    m
}

//! A FIX message: header, body, and trailer field maps.

use crate::error::DecodeError;
use crate::field_map::FieldMap;
use crate::tags::{BEGIN_STRING, MSG_TYPE};

/// A FIX message split into header, body, and trailer regions.
///
/// Decoding routes session-level header tags and trailer tags to their regions; everything
/// else lands in the body. Encoding always emits the canonical order
/// `8, 9, 35, <rest of header>, <body>, <trailer except 10>, 10`.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct Message {
    /// Header fields (BeginString, BodyLength, MsgType, session fields, ...).
    pub header: FieldMap,
    /// Application/body fields.
    pub body: FieldMap,
    /// Trailer fields (SignatureLength, Signature, CheckSum).
    pub trailer: FieldMap,
}

impl Message {
    /// Create an empty message.
    pub fn new() -> Self {
        Self::default()
    }

    /// The BeginString (tag 8) as a string, if present and valid UTF-8.
    pub fn begin_string(&self) -> Option<&str> {
        self.header.get(BEGIN_STRING).and_then(|f| f.as_str().ok())
    }

    /// The MsgType (tag 35) as a string, if present and valid UTF-8.
    pub fn msg_type(&self) -> Option<&str> {
        self.header.get(MSG_TYPE).and_then(|f| f.as_str().ok())
    }

    /// Encode to wire bytes (computes BodyLength and CheckSum).
    pub fn encode(&self) -> Vec<u8> {
        crate::codec::encode(self)
    }

    /// Decode from wire bytes (verifies BodyLength and CheckSum).
    pub fn decode(bytes: &[u8]) -> Result<Self, DecodeError> {
        crate::codec::decode(bytes)
    }
}

//! FIX fields and their typed value converters.

use rust_decimal::Decimal;
use time::OffsetDateTime;

use crate::error::FieldError;

/// A single FIX field: a tag number and its raw (wire) value bytes.
///
/// Raw bytes are preserved verbatim so re-encoding reproduces the original representation
/// (round-trip fidelity, FR-B9). Typed accessors convert on demand and never panic.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Field {
    tag: u32,
    value: Vec<u8>,
}

impl Field {
    /// Create a field from a tag and raw value bytes.
    pub fn new(tag: u32, value: impl Into<Vec<u8>>) -> Self {
        Self {
            tag,
            value: value.into(),
        }
    }

    /// Create a field from a tag and a string value.
    pub fn string(tag: u32, value: &str) -> Self {
        Self::new(tag, value.as_bytes().to_vec())
    }

    /// Create an integer-valued field.
    pub fn int(tag: u32, value: i64) -> Self {
        Self::new(tag, value.to_string().into_bytes())
    }

    /// The field's tag number.
    pub fn tag(&self) -> u32 {
        self.tag
    }

    /// The raw value bytes.
    pub fn value_bytes(&self) -> &[u8] {
        &self.value
    }

    /// The value as a UTF-8 string slice.
    pub fn as_str(&self) -> Result<&str, FieldError> {
        core::str::from_utf8(&self.value).map_err(|_| FieldError::NotUtf8 { tag: self.tag })
    }

    /// The value as an integer.
    pub fn as_int(&self) -> Result<i64, FieldError> {
        let s = self.as_str()?;
        s.trim().parse().map_err(|_| FieldError::NotInt {
            tag: self.tag,
            value: s.to_owned(),
        })
    }

    /// The value as a fixed-precision decimal (FIX Price/Qty/Amt).
    pub fn as_decimal(&self) -> Result<Decimal, FieldError> {
        let s = self.as_str()?;
        s.trim().parse().map_err(|_| FieldError::NotDecimal {
            tag: self.tag,
            value: s.to_owned(),
        })
    }

    /// The value as a single character (FIX char).
    pub fn as_char(&self) -> Result<char, FieldError> {
        let s = self.as_str()?;
        let mut chars = s.chars();
        match (chars.next(), chars.next()) {
            (Some(c), None) => Ok(c),
            _ => Err(FieldError::NotChar {
                tag: self.tag,
                value: s.to_owned(),
            }),
        }
    }

    /// The value as a boolean (`Y`/`N`).
    pub fn as_bool(&self) -> Result<bool, FieldError> {
        match self.value.as_slice() {
            b"Y" => Ok(true),
            b"N" => Ok(false),
            _ => Err(FieldError::NotBool {
                tag: self.tag,
                value: String::from_utf8_lossy(&self.value).into_owned(),
            }),
        }
    }

    /// The value as a UTC timestamp. Accepts up to picosecond fractional digits and
    /// truncates to nanosecond resolution (FR-B7).
    pub fn as_utc_timestamp(&self) -> Result<OffsetDateTime, FieldError> {
        let s = self.as_str()?;
        parse_utc_timestamp(s).ok_or_else(|| FieldError::NotTimestamp {
            tag: self.tag,
            value: s.to_owned(),
        })
    }
}

/// Parse `YYYYMMDD-HH:MM:SS[.fraction]` as UTC. Returns `None` on any malformation.
fn parse_utc_timestamp(s: &str) -> Option<OffsetDateTime> {
    let (date, time_part) = s.split_once('-')?;
    if date.len() != 8 {
        return None;
    }
    let year: i32 = date.get(0..4)?.parse().ok()?;
    let month: u8 = date.get(4..6)?.parse().ok()?;
    let day: u8 = date.get(6..8)?.parse().ok()?;

    let (hms, frac) = match time_part.split_once('.') {
        Some((h, f)) => (h, Some(f)),
        None => (time_part, None),
    };
    let mut parts = hms.split(':');
    let hour: u8 = parts.next()?.parse().ok()?;
    let min: u8 = parts.next()?.parse().ok()?;
    let sec: u8 = parts.next()?.parse().ok()?;
    if parts.next().is_some() {
        return None;
    }

    // Accept >= 1 fractional digits up to picosecond; truncate to nanosecond (first 9 digits).
    let nanos: u32 = match frac {
        None => 0,
        Some(f) => {
            if f.is_empty() || !f.bytes().all(|b| b.is_ascii_digit()) {
                return None;
            }
            let mut buf = [b'0'; 9];
            for (slot, digit) in buf.iter_mut().zip(f.bytes()) {
                *slot = digit;
            }
            core::str::from_utf8(&buf).ok()?.parse().ok()?
        }
    };

    let month = time::Month::try_from(month).ok()?;
    let date = time::Date::from_calendar_date(year, month, day).ok()?;
    let time = time::Time::from_hms_nano(hour, min, sec, nanos).ok()?;
    Some(time::PrimitiveDateTime::new(date, time).assume_utc())
}
